Action.Str:
{
  "type": "Column",
  "padding": 12,
  "backgroundColor": "%widget_color_background",
  "cornerRadius": "%widget_corner_radius",
  "fillMaxSize": true,
  "children": [
    {
      "type": "Row",
      "fillMaxWidth": true,
      "verticalAlignment": "Center",
      "children": [
        {
          "type": "Text",
          "text": "%team1_name",
          "color": "%widget_color_text",
          "textSize": 16,
          "isWeighted": true,
          "paddingEnd": 8
        },
        {
          "type": "Text",
          "text": "%team1_score",
          "color": "%widget_color_score_text",
          "textSize": 16,
          "bold": true
        }
      ]
    },
    {
      "type": "Spacer",
      "size": 4
    },
    {
      "type": "Row",
      "fillMaxWidth": true,
      "verticalAlignment": "Center",
      "children": [
        {
          "type": "Text",
          "text": "%team2_name",
          "color": "%widget_color_text",
          "textSize": 16,
          "isWeighted": true,
          "paddingEnd": 8
        },
        {
          "type": "Text",
          "text": "%team2_score",
          "color": "%widget_color_score_text",
          "textSize": 16,
          "bold": true
        }
      ]
    },
    {
      "type": "Spacer",
      "size": 8
    },
    {
      "type": "Text",
      "text": "%match_summary",
      "color": "%widget_color_text",
      "textSize": 14,
      "align": "Center",
      "fillMaxWidth": true
    }
  ]
}
